      "invoiceCodes": [
        "INV-001",
        "INV-002",
        "INV-003"
      ]
    }
  }
}

Increment variable failCount by 1 and return the next value.
{
  "wf": {
    "vars": {
      "failCount": 2
    }
  }
}

Увеличивай значение переменной reprocess_count на каждой итерации и верни результат в поле reprocess_count.
{
  "wf": {
    "vars": {
      "reprocess_count": 4
    }
  }
}

For the previous REST response clear values in fields ORDER_ID, STATE, COMMENT and remove every other key.
{
  "wf": {
    "vars": {
      "RESTbody": {
        "result": [
          {
            "ORDER_ID": "O-1001",
            "STATE": "created",
            "COMMENT": "ok",
            "AMOUNT": "500",
            "CURRENCY": "USD"
          },
          {
            "ORDER_ID": "O-1002",
            "STATE": "failed",
            "COMMENT": "retry",
            "ERROR_CODE": "E17",
            "DETAILS": "network"
          }
        ]
      }
    }
  }
}

